def is_chi(text):
    if not text:
        return False
    # Check first 10000 chars
    header = text[:10000]
    triggers = ["CHI '", "CHI 20", "CHI'", "CHI1", "CHI 1"]
    for t in triggers:
        if t in header:
            return True
    if "Conference on Human Factors in Computing Systems" in header:
        return True
    return False

total_citations = 0
count = 0
papers_found = []

