        fn = paper.get('filename')
        if fn in citation_map:
            total_citations += citation_map[fn]
            count += 1
            papers_found.append(fn)

print("__RESULT__:")
print(json.dumps({"total": total_citations, "count": count, "papers_found": papers_found}))
